from __future__ import annotations

import threading
import types
from typing import Optional

from ._exceptions import ExceptionMapping, PoolTimeout, map_exceptions

# Our async synchronization primitives use either 'anyio' or 'trio' depending
# on if they're running under asyncio or trio.

try:
    import trio
except (ImportError, NotImplementedError):  # pragma: nocover
    trio = None  # type: ignore

try:
    import anyio
except ImportError:  # pragma: nocover
    anyio = None  # type: ignore


def current_async_library() -> str:
    """
    Determine the current asynchronous library in use.

    Returns:
        A string identifying the async environment: either "asyncio" or "trio".

    Raises:
        RuntimeError: If an unsupported async environment is detected or
            the required extra package for the detected environment is missing.
    """
    # Determine if we're running under trio or asyncio.
    # See https://sniffio.readthedocs.io/en/latest/
    try:
        import sniffio
    except ImportError:  # pragma: nocover
        environment = "asyncio"
    else:
        environment = sniffio.current_async_library()

    if environment not in ("asyncio", "trio"):  # pragma: nocover
        raise RuntimeError("Running under an unsupported async environment.")

    if environment == "asyncio" and anyio is None:  # pragma: nocover
        raise RuntimeError(
            "Running with asyncio requires installation of 'httpcore[asyncio]'."
        )

    if environment == "trio" and trio is None:  # pragma: nocover
        raise RuntimeError(
            "Running with trio requires installation of 'httpcore[trio]'."
        )

    return environment


class AsyncLock:
    """
    An asynchronous lock that delegates to Trio or AnyIO depending on the
    detected async library. Use with 'async with'.
    """

    def __init__(self) -> None:
        """
        Initialize the AsyncLock.

        The actual backend lock is created lazily when the lock is first used,
        based on the current async library.
        """
        self._backend = ""

    def setup(self) -> None:
        """
        Detect if we're running under 'asyncio' or 'trio' and create
        a lock with the correct implementation.
        """
        self._backend = current_async_library()
        if self._backend == "trio":
            self._trio_lock = trio.Lock()
        elif self._backend == "asyncio":
            self._anyio_lock = anyio.Lock()

    async def __aenter__(self) -> "AsyncLock":
        """
        Acquire the lock asynchronously and return the lock instance.

        This will initialize the lock backend if not already set up.
        """
        if not self._backend:
            self.setup()

        if self._backend == "trio":
            await self._trio_lock.acquire()
        elif self._backend == "asyncio":
            await self._anyio_lock.acquire()

        return self

    async def __aexit__(
        self,
        exc_type: type[BaseException] | None = None,
        exc_value: BaseException | None = None,
        traceback: types.TracebackType | None = None,
    ) -> None:
        """
        Release the lock when exiting the async context manager.
        """
        if self._backend == "trio":
            self._trio_lock.release()
        elif self._backend == "asyncio":
            self._anyio_lock.release()


class AsyncThreadLock:
    """
    A no-op "async" context manager for code paths that are expected to run
    in thread-only contexts where no asynchronous I/O is performed.

    Using this in an async context simply does nothing and is useful for API
    compatibility where a lock-like object is required but no actual locking
    is necessary for async tasks.
    """

    def __enter__(self) -> "AsyncThreadLock":
        """
        Enter the (synchronous) context manager.

        Returns:
            The context manager instance.
        """
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None = None,
        exc_value: BaseException | None = None,
        traceback: types.TracebackType | None = None,
    ) -> None:
        """
        Exit the (synchronous) context manager. No operation is performed.
        """
        pass


class AsyncEvent:
    """
    An asynchronous event primitive that works with either Trio or AnyIO.

    Use 'await event.wait()' to wait for the event to be set, and
    'event.set()' to set it.
    """

    def __init__(self) -> None:
        """
        Initialize the AsyncEvent.

        The backend event is created lazily when first used.
        """
        self._backend = ""

    def setup(self) -> None:
        """
        Detect if we're running under 'asyncio' or 'trio' and create
        an event with the correct implementation.
        """
        self._backend = current_async_library()
        if self._backend == "trio":
            self._trio_event = trio.Event()
        elif self._backend == "asyncio":
            self._anyio_event = anyio.Event()

    def set(self) -> None:
        """
        Set the event, waking up any waiters.
        """
        if not self._backend:
            self.setup()

        if self._backend == "trio":
            self._trio_event.set()
        elif self._backend == "asyncio":
            self._anyio_event.set()

    async def wait(self, timeout: Optional[float] = None) -> None:
        """
        Wait until the event is set, with an optional timeout.

        Args:
            timeout: The number of seconds to wait before timing out. If None,
                wait indefinitely.

        Raises:
            PoolTimeout: If the wait operation times out.
        """
        if not self._backend:
            self.setup()

        if self._backend == "trio":
            # Map Trio timeout to PoolTimeout.
            trio_exc_map: ExceptionMapping = {getattr(trio, "TooSlowError", Exception): PoolTimeout}
            try:
                if timeout is None:
                    await self._trio_event.wait()
                else:
                    with map_exceptions(trio_exc_map):
                        with trio.fail_after(timeout):
                            await self._trio_event.wait()
            except getattr(trio, "TooSlowError", TimeoutError):  # pragma: nocover
                raise PoolTimeout() from None
        elif self._backend == "asyncio":
            # AnyIO's fail_after raises a TimeoutError on timeout; map to PoolTimeout.
            try:
                if timeout is None:
                    await self._anyio_event.wait()
                else:
                    with anyio.fail_after(timeout):
                        await self._anyio_event.wait()
            except TimeoutError:
                raise PoolTimeout() from None


class ThreadEvent:
    """
    A threading.Event wrapper to provide a synchronous event primitive.
    """

    def __init__(self) -> None:
        """
        Initialize the ThreadEvent with an internal threading.Event.
        """
        self._event = threading.Event()

    def set(self) -> None:
        """
        Set the event, waking up all waiters.
        """
        self._event.set()

    def clear(self) -> None:
        """
        Clear the event.
        """
        self._event.clear()

    def wait(self, timeout: Optional[float] = None) -> bool:
        """
        Block until the event is set or the optional timeout elapses.

        Returns:
            True if the event is set, False if the timeout occurred.
        """
        return self._event.wait(timeout=timeout)


class Semaphore:
    """
    A semaphore supporting both asynchronous (AnyIO/Trio) and synchronous
    (threading) usage via separate methods.
    """

    def __init__(self, value: int = 1) -> None:
        """
        Initialize the semaphore.

        Args:
            value: The initial semaphore counter.
        """
        self._value = value
        self._lock = threading.Lock()
        # Async backends will be created lazily.
        self._backend = ""

    def setup_async(self) -> None:
        """
        Lazily create an async semaphore backend depending on the current
        async library.
        """
        if not self._backend:
            self._backend = current_async_library()
            if self._backend == "trio":
                self._trio_sem = trio.Semaphore(self._value)
            elif self._backend == "asyncio":
                self._anyio_sem = anyio.Semaphore(self._value)

    # Synchronous API
    def acquire(self, timeout: Optional[float] = None) -> bool:
        """
        Acquire the semaphore in a blocking manner.

        Args:
            timeout: Optional timeout in seconds. If None, block indefinitely.

        Returns:
            True if acquired, False on timeout.
        """
        # threading.Semaphore supports a timeout directly; emulate with Lock + counter.
        end = None if timeout is None else (threading._time() + timeout)
        while True:
            with self._lock:
                if self._value > 0:
                    self._value -= 1
                    return True
            if timeout is not None:
                if threading._time() >= end:  # type: ignore[attr-defined]
                    return False
            # Small sleep to avoid busy loop.
            threading.Event().wait(0.01)

    def release(self) -> None:
        """
        Release the semaphore, incrementing the internal counter and waking waiters.
        """
        with self._lock:
            self._value += 1

    # Asynchronous API
    async def acquire_async(self, timeout: Optional[float] = None) -> None:
        """
        Acquire the semaphore in an async context.

        Args:
            timeout: Optional timeout in seconds. If provided and the wait times out,
                a PoolTimeout is raised.
        """
        self.setup_async()
        if self._backend == "trio":
            try:
                if timeout is None:
                    await self._trio_sem.acquire()
                else:
                    with trio.fail_after(timeout):
                        await self._trio_sem.acquire()
            except getattr(trio, "TooSlowError", TimeoutError):
                raise PoolTimeout() from None
        elif self._backend == "asyncio":
            try:
                if timeout is None:
                    await self._anyio_sem.acquire()
                else:
                    with anyio.fail_after(timeout):
                        await self._anyio_sem.acquire()
            except TimeoutError:
                raise PoolTimeout() from None

    async def release_async(self) -> None:
        """
        Release the async semaphore.
        """
        self.setup_async()
        if self._backend == "trio":
            self._trio_sem.release()
        elif self._backend == "asyncio":
            self._anyio_sem.release()


class SyncLock:
    """
    A simple threading lock that can be used as a context manager.
    """

    def __init__(self) -> None:
        """
        Initialize the SyncLock with an underlying threading.Lock.
        """
        self._lock = threading.Lock()

    def __enter__(self) -> "SyncLock":
        """
        Acquire the threading lock when entering the context.
        """
        self._lock.acquire()
        return self

    def __exit__(
        self,
        exc_type: type[BaseException] | None = None,
        exc_value: BaseException | None = None,
        traceback: types.TracebackType | None = None,
    ) -> None:
        """
        Release the threading lock when exiting the context.
        """
        self._lock.release()